window.PACTO.acts["reg-2013-1052"]={"label": "REGOLAMENTO (UE) N. 1052/2013 DEL PARLAMENTO EUROPEO E DEL CONSIGLIO", "short": "Reg. 1052/2013", "file": "ext-reg-2013-1052.html", "external": true, "version": "originale GU", "eurlex": "https://eur-lex.europa.eu/eli/reg/2013/1052/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Oggetto", "anchor": "art_1", "frags": [[null, "<p class=\"oj-normal\">Il presente regolamento istituisce un quadro comune per lo scambio di informazioni e per la cooperazione tra gli Stati membri e l'Agenzia al fine di migliorare la conoscenza situazionale e di aumentare la capacità di reazione alle frontiere esterne degli Stati membri dell'Unione («frontiere esterne»), al fine di individuare, prevenire e combattere l'immigrazione clandestina e la criminalità transfrontaliera e contribuire a garantire la protezione e la salvezza della vita dei migranti («EUROSUR»).</p>"]]}, "2": {"label": "Articolo 2", "heading": "Ambito di applicazione", "anchor": "art_2", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il presente regolamento si applica alla sorveglianza delle frontiere esterne terrestri e marittime, inclusi il monitoraggio, l'individuazione, l'identificazione, la localizzazione, la prevenzione e l'intercettazione degli attraversamenti non autorizzati delle frontiere al fine di individuare, prevenire e combattere l'immigrazione clandestina e la criminalità transfrontaliera e contribuire a garantire la protezione e la salvezza della vita dei migranti.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il presente regolamento può applicarsi altresì alla sorveglianza delle frontiere aeree, nonché ai controlli ai valichi di frontiera, qualora gli Stati membri forniscano volontariamente tali informazioni a EUROSUR.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il presente regolamento non si applica ad eventuali misure giuridiche o amministrative adottate una volta che le autorità competenti di uno Stato membro abbiano intercettato attività criminali transfrontaliere o attraversamenti non autorizzati delle frontiere esterne.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Nell'applicare il presente regolamento gli Stati membri e l'Agenzia rispettano i diritti fondamentali, in particolare i principi di non respingimento e di rispetto della dignità umana e gli obblighi di protezione dei dati. Essi considerano prioritarie le speciali esigenze dei minori, dei minori non accompagnati, delle vittime della tratta di esseri umani, delle persone bisognose di assistenza medica urgente, delle persone bisognose di protezione internazionale, di quanti si trovano in pericolo in mare e di chiunque si trovi in una situazione di particolare vulnerabilità.</p>\n</div>"]]}, "3": {"label": "Articolo 3", "heading": "Definizioni", "anchor": "art_3", "frags": [[null, "<p class=\"oj-normal\">Ai fini del presente regolamento, si intende per:</p>"], [null, "<p class=\"oj-normal\">a)   <span class=\"oj-bold\">«Agenzia»</span>: l'Agenzia europea per la gestione della cooperazione operativa alle frontiere esterne degli Stati membri dell'Unione europea, istituita dal regolamento (CE) n. 2007/2004;</p>"], [null, "<p class=\"oj-normal\">b)   <span class=\"oj-bold\">«conoscenza situazionale»</span>: la capacità di monitorare, individuare, identificare, localizzare e comprendere le attività illegali transfrontaliere allo scopo di motivare le misure di reazione, combinando nuove informazioni alle conoscenze già acquisite ed essere maggiormente in grado di ridurre le perdite di vite umane di migranti alle frontiere esterne, lungo le stesse o in loro prossimità;</p>"], [null, "<p class=\"oj-normal\">c)   <span class=\"oj-bold\">«capacità di reazione»</span>: la capacità di intraprendere azioni dirette a contrastare attività transfrontaliere illegali alle frontiere esterne, lungo le stesse o in loro prossimità, compresi i mezzi e i tempi necessari per reagire adeguatamente;</p>"], [null, "<p class=\"oj-normal\">d)   <span class=\"oj-bold\">«quadro situazionale»</span>: un'interfaccia grafica per presentare quasi in tempo reale dati e informazioni trasmessi da varie autorità, sensori, piattaforme e altre fonti, che sono condivisi con altre autorità mediante canali di comunicazione e informazione allo scopo di ottenere una conoscenza situazionale e sostenere la capacità di reazione lungo le frontiere esterne e nella zona pre-frontaliera;</p>"], [null, "<p class=\"oj-normal\">e)   <span class=\"oj-bold\">«reati di criminalità transfrontaliera»</span>: un reato grave avente una dimensione transfrontaliera perpetrato alle frontiere esterne, lungo le stesse o in loro prossimità;</p>"], [null, "<p class=\"oj-normal\">f)   <span class=\"oj-bold\">«sezione di frontiera esterna»</span>: l'intera frontiera esterna terrestre o marittima di uno Stato membro o parte di essa, quale definita dal diritto nazionale o determinata dal centro nazionale di coordinamento o da altra autorità nazionale responsabile;</p>"], [null, "<p class=\"oj-normal\">g)   <span class=\"oj-bold\">«zona pre-frontaliera»</span>: l'area geografica situata oltre le frontiere esterne;</p>"], [null, "<p class=\"oj-normal\">h)   <span class=\"oj-bold\">«situazioni di crisi»</span>: catastrofi naturali o provocate dall'uomo, incidenti, crisi umanitarie o politiche o altri episodi gravi che si verificano alle frontiere esterne, lungo le stesse o in loro prossimità e che possono avere un'incidenza significativa sul controllo delle frontiere esterne;</p>"], [null, "<p class=\"oj-normal\">i)   <span class=\"oj-bold\">«episodio»</span>: una situazione connessa all'immigrazione clandestina, alla criminalità transfrontaliera o ad un rischio per la vita dei migranti alle frontiere esterne, lungo le stesse o in loro prossimità.</p>"]]}, "4": {"label": "Articolo 4", "heading": "Struttura di EUROSUR", "anchor": "art_4", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Per lo scambio di informazioni e la cooperazione nel campo della sorveglianza di frontiera e tenendo in considerazione i meccanismi esistenti di scambio di informazioni e cooperazione, gli Stati membri e l'Agenzia utilizzano la struttura di EUROSUR che consiste delle seguenti componenti:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">centri nazionali di coordinamento;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">quadri situazionali nazionali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">rete di comunicazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">quadro situazionale europeo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">quadro comune di intelligence pre-frontaliera;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">applicazione comune degli strumenti di sorveglianza.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   I centri nazionali di coordinamento forniscono all'Agenzia, tramite la rete di comunicazione, le informazioni tratte dai loro quadri situazionali nazionali che sono necessarie per istituire e aggiornare il quadro situazionale europeo e il quadro comune di intelligence pre-frontaliera.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Agenzia conferisce ai centri nazionali di coordinamento, tramite la rete di comunicazione, accesso illimitato al quadro situazionale europeo e al quadro comune di intelligence pre-frontaliera.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Le componenti elencate al paragrafo 1 sono istituite e gestite secondo i principi stabiliti in allegato.</p>\n</div>"]]}, "5": {"label": "Articolo 5", "heading": "Centro nazionale di coordinamento", "anchor": "art_5", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Ogni Stato membro istituisce, attiva e gestisce un centro nazionale di coordinamento che provvede al coordinamento e allo scambio di informazioni tra tutte le autorità incaricate della sorveglianza delle frontiere esterne a livello nazionale, con gli altri centri nazionali di coordinamento e con l'Agenzia. Ogni Stato membro comunica l'istituzione del proprio centro nazionale di coordinamento alla Commissione, che ne informa immediatamente gli altri Stati membri e l'Agenzia.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Fatto salvo l'articolo 17 e nell'ambito della struttura di EUROSUR, il centro nazionale di coordinamento costituisce l'unico punto di contatto per lo scambio di informazioni e la cooperazione con altri centri nazionali di coordinamento e con l'Agenzia.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il centro nazionale di coordinamento:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">provvede allo scambio tempestivo di informazioni e alla cooperazione tempestiva tra tutte le autorità nazionali responsabili della sorveglianza delle frontiere esterne, nonché con gli altri centri nazionali di coordinamento e con l'Agenzia;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">provvede allo scambio tempestivo di informazioni, a livello nazionale, con le autorità responsabili della ricerca e salvataggio, delle attività di contrasto, dell'asilo e dell'immigrazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">contribuisce alla gestione efficace ed efficiente delle risorse e del personale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">istituisce e aggiorna il quadro situazionale nazionale in conformità dell'articolo 9;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">assiste la pianificazione e l'attuazione delle attività nazionali di sorveglianza di frontiera;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">coordina il sistema nazionale di sorveglianza delle frontiere, in conformità del diritto nazionale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">contribuisce a misurare a scadenze regolari gli effetti delle attività nazionali di sorveglianza di frontiera ai fini del presente regolamento;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">coordina le misure operative con altri Stati membri, fatte salve le competenze dell'Agenzia e degli Stati membri.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il centro nazionale di coordinamento è operativo 24 ore su 24 e 7 giorni su 7.</p>\n</div>"]]}, "6": {"label": "Articolo 6", "heading": "L'Agenzia", "anchor": "art_6", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">istituisce e aggiorna la rete di comunicazione di EUROSUR in conformità dell'articolo 7;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">istituisce e aggiorna il quadro situazionale europeo in conformità dell'articolo 10;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">istituisce e aggiorna il quadro comune di intelligence pre-frontaliera in conformità dell'articolo 11;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">coordina l'applicazione comune degli strumenti di sorveglianza in conformità dell'articolo 12.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Ai fini del paragrafo 1, l'Agenzia è operativa 24 ore su 24 e 7 giorni su 7.</p>\n</div>"]]}, "7": {"label": "Articolo 7", "heading": "Rete di comunicazione", "anchor": "art_7", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia istituisce e aggiorna una rete per la comunicazione, al fine di fornire strumenti di comunicazione e analisi e consentire lo scambio di informazioni sensibili non classificate e di informazioni classificate, in modo sicuro e quasi in tempo reale, con i centri nazionali di coordinamento e tra questi ultimi. La rete è operativa 24 ore su 24 e 7 giorni su 7 e provvede ai seguenti compiti:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">scambio bilaterale e multilaterale di informazioni quasi in tempo reale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">audioconferenze e videoconferenze;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">gestione, conservazione, trasmissione e trattamento sicuri di informazioni sensibili non classificate;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">gestione, conservazione, trasmissione e trattamento sicuri di informazioni classificate UE fino al livello RESTREINT UE/EU RESTRICTED o a livelli di classifica nazionali equivalenti, garantendo che le informazioni classificate siano gestite, archiviate, trasmesse e trattate in una sezione distinta e debitamente accreditata della rete di comunicazione.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia fornisce assistenza tecnica e garantisce che la rete di comunicazione sia interoperabile con ogni altro sistema di comunicazione e informazione pertinente gestito dall'Agenzia.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Conformemente all'articolo 11 quinquies del regolamento (CE) n. 2007/2004, l'Agenzia scambia, tratta e conserva informazioni sensibili non classificate e informazioni classificate nella rete di comunicazione.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   I centri nazionali di coordinamento scambiano, trattano e conservano informazioni sensibili non classificate e informazioni classificate nella rete di comunicazione secondo regole e norme equivalenti a quelle stabilite nel regolamento interno della Commissione (<span class=\"oj-super oj-note-tag\">15</span>).</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Le autorità, le agenzie e gli altri organismi degli Stati membri che utilizzano la rete di comunicazione si assicurano che le informazioni classificate siano gestite secondo regole e norme di sicurezza equivalenti a quelle applicate dall'Agenzia.</p>\n</div>"]]}, "8": {"label": "Articolo 8", "heading": "Quadri situazionali", "anchor": "art_8", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   I quadri situazionali nazionali, il quadro situazionale europeo e il quadro comune di intelligence pre-frontaliera risultano dalla raccolta e valutazione, dal confronto, dall'analisi e interpretazione, dalla produzione, visualizzazione e divulgazione di informazioni.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   I quadri di cui al paragrafo 1 comprendono i seguenti livelli:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">livello «eventi»;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">livello «operazioni»;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">livello «analisi».</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"]]}, "9": {"label": "Articolo 9", "heading": "Quadro situazionale nazionale", "anchor": "art_9", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il centro nazionale di coordinamento istituisce e aggiorna un quadro situazionale nazionale per fornire informazioni efficaci, esatte e tempestive a tutte le autorità responsabili a livello nazionale del controllo e, in particolare, della sorveglianza delle frontiere esterne.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il quadro situazionale nazionale consta delle informazioni raccolte dalle seguenti fonti:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sistema nazionale di sorveglianza di frontiera, in conformità del diritto nazionale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sensori stazionari e mobili gestiti da autorità nazionali responsabili della sorveglianza delle frontiere esterne;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">pattugliamenti per la sorveglianza di frontiera e altre missioni di monitoraggio;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">centri di coordinamento locali, regionali e di altro tipo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">altre autorità e altri sistemi nazionali pertinenti, inclusi ufficiali di collegamento, centri operativi e punti di contatto;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">Agenzia;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">centri nazionali di coordinamento degli altri Stati membri;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">autorità dei paesi terzi, in base agli accordi bilaterali o multilaterali e alle reti regionali di cui all'articolo 18;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sistemi di segnalazione delle navi, secondo le rispettive basi giuridiche;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">altre organizzazioni europee e internazionali competenti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">k)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">altre fonti.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il livello «eventi» del quadro situazionale nazionale comprende i seguenti sottolivelli:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sottolivello sull'attraversamento non autorizzato delle frontiere, ivi incluse le informazioni, disponibili presso il centro nazionale di coordinamento, sugli episodi connessi ad un rischio per la vita dei migranti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sottolivello «reati di criminalità transfrontaliera»;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sottolivello «situazioni di crisi»;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sottolivello «altri eventi», contenente informazioni su veicoli, imbarcazioni e altri mezzi e persone non identificati e sospetti presenti alle frontiere esterne dello Stato membro interessato, lungo le stesse o in loro prossimità, e su qualsiasi altro evento che potrebbe avere un'incidenza significativa sul controllo delle frontiere esterne.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il centro nazionale di coordinamento attribuisce un unico livello di impatto indicativo, «basso», «medio» o «alto», a ogni episodio registrato nel livello «eventi» del quadro situazionale nazionale. Tutti gli episodi sono comunicati all'Agenzia.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il livello «operazioni» del quadro situazionale nazionale comprende i seguenti sottolivelli:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sottolivello «mezzi propri, inclusi mezzi militari di assistenza ad una missione relativa ad attività di contrasto e aree operative», che contiene informazioni sulla posizione, lo stato e il tipo dei mezzi propri e sulle autorità coinvolte. Per quanto riguarda i mezzi militari di assistenza ad una missione relativa ad attività di contrasto, il centro nazionale di coordinamento può decidere, su richiesta dell'autorità nazionale responsabile di tali mezzi, di restringere l'accesso alle informazioni in base al principio della necessità di sapere;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sottolivello «informazioni ambientali», che contiene o permette di accedere a informazioni sulle condizioni del terreno e meteorologiche alle frontiere esterne dello Stato membro interessato.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Le informazioni sui mezzi propri del livello «operazioni» sono classificate RESTREINT UE/EU RESTRICTED.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Il livello «analisi» del quadro situazionale nazionale comprende i seguenti sottolivelli:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sottolivello «informazioni», contenente le principali evoluzioni e gli indicatori che sono rilevanti ai fini del presente regolamento.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sottolivello «prodotti analitici», che include relazioni analitiche, tendenze della valutazione dei rischi, osservazioni regionali e note informative che sono rilevanti ai fini del presente regolamento;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sottolivello «intelligence», contenente informazioni analizzate che sono rilevanti ai fini del presente regolamento e, in particolare, per l'attribuzione dei livelli di impatto alle sezioni di frontiere esterne,</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sottolivello «immagini e geodati», che include immagini di riferimento, mappe di contesto, validità delle informazioni analizzate e analisi dei cambiamenti (immagini di osservazione della terra) nonché rilevazione dei cambiamenti, dati georeferenziati e mappe di permeabilità delle frontiere esterne.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Le informazioni contenute nel livello «analisi» e le informazioni ambientali del livello «operazioni» del quadro situazionale nazionale possono basarsi sui dati forniti dal quadro situazionale europeo e dal quadro comune di intelligence pre-frontaliera.</p>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   I centri nazionali di coordinamento degli Stati membri vicini si comunicano direttamente e quasi in tempo reale il quadro situazionale delle sezioni di frontiera esterna vicine per quanto riguarda:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">episodi e altri eventi significativi contenuti nel livello «eventi»;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">relazioni tattiche di analisi dei rischi, contenute nel livello «analisi».</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [10, "<div>\n<p class=\"oj-normal\">10.   I centri nazionali di coordinamento degli Stati membri vicini possono comunicarsi direttamente e quasi in tempo reale il quadro situazionale delle sezioni di frontiera esterna vicine per quanto riguarda le posizioni, lo stato e il tipo di mezzi propri che operano nelle sezioni di frontiera esterna vicine contenute nel livello «operazioni».</p>\n</div>"]]}, "10": {"label": "Articolo 10", "heading": "Quadro situazionale europeo", "anchor": "art_10", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia istituisce e aggiorna un quadro situazionale europeo per fornire ai centri nazionali di coordinamento informazioni e analisi efficaci, esatte e tempestive.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il quadro situazionale europeo consta delle informazioni raccolte dalle seguenti fonti:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">quadri situazionali nazionali nella misura prevista dal presente articolo,</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">Agenzia;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">Commissione, che fornisce informazioni strategiche sul controllo delle frontiere nonché sulle carenze rilevate nello svolgimento del controllo delle frontiere esterne;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">delegazioni e uffici dell'Unione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">altri organi, organismi e servizi dell'Unione e organizzazioni internazionali competenti, di cui all'articolo 17;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">altre fonti.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il livello «eventi» del quadro situazionale europeo contiene informazioni su:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">episodi e altri eventi contenuti nel livello «eventi» del quadro situazionale nazionale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">episodi e altri eventi contenuti nel quadro comune di intelligence pre-frontaliera;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">episodi nell'area operativa di un'operazione congiunta, di un progetto pilota o di un intervento rapido coordinati dall'Agenzia.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Nel quadro situazionale europeo l'Agenzia tiene conto del livello di impatto che il centro nazionale di coordinamento ha attribuito a un determinato episodio nel quadro situazionale nazionale.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il livello «operazioni» del quadro situazionale europeo comprende i seguenti sottolivelli:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sottolivello «mezzi propri», contenente informazioni sulla posizione, l'ora, lo stato e il tipo di mezzi che partecipano alle operazioni congiunte, ai progetti pilota e agli interventi rapidi dell'Agenzia o messi a disposizione di quest'ultima, e il piano di dispiegamento, compresa l'area di operazione, gli orari di pattugliamento e i codici di comunicazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sottolivello «operazioni», contenente informazioni sulle operazioni congiunte, i progetti pilota e gli interventi rapidi coordinati dall'Agenzia, compresi il mandato della missione, l'ubicazione, la situazione, la durata, informazioni sugli Stati membri e su altri attori coinvolti, relazioni sulla situazione quotidiana e settimanale, dati statistici e fascicoli informativi per i media;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sottolivello «informazioni ambientali», che include informazioni sulle condizioni del terreno e meteorologiche alle frontiere esterne.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Le informazioni sui mezzi propri del livello «operazioni» del quadro situazionale europeo sono classificate RESTREINT UE/EU RESTRICTED.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Il livello «analisi» del quadro situazionale europeo è strutturato nello stesso modo di quello del quadro situazionale nazionale stabilito all'articolo 9, paragrafo 7.</p>\n</div>"]]}, "11": {"label": "Articolo 11", "heading": "Quadro comune di intelligence pre-frontaliera", "anchor": "art_11", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia istituisce e aggiorna un quadro comune di intelligence pre-frontaliera per fornire ai centri nazionali di coordinamento informazioni e analisi efficaci, esatte e tempestive sulla zona pre-frontaliera.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il quadro comune di intelligence pre-frontaliera consta delle informazioni raccolte dalle seguenti fonti:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">centri nazionali di coordinamento, comprese informazioni e relazioni ricevute dagli ufficiali di collegamento degli Stati membri attraverso le autorità nazionali competenti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">delegazioni e uffici dell'Unione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">Agenzia, comprese le informazioni e le relazioni ricevute dai suoi ufficiali di collegamento;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">altri organi, organismi e servizi dell'Unione e organizzazioni internazionali competenti di cui all'articolo 18;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">autorità dei paesi terzi, in base agli accordi bilaterali o multilaterali e alle reti regionali di cui all'articolo 20, attraverso i centri nazionali di coordinamento.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">altre fonti.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il quadro comune di intelligence pre-frontaliera può contenere informazioni utili per le operazioni di sorveglianza delle frontiere aeree e per le verifiche ai valichi di frontiera esterni.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   I livelli «eventi», «operazioni» e «analisi» del quadro comune di intelligence pre-frontaliera sono strutturati nello stesso modo del quadro situazionale europeo stabilito all'articolo 10.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   L'Agenzia attribuisce un unico livello di impatto indicativo a ogni episodio del livello «eventi» del quadro comune di intelligence pre-frontaliera. L'Agenzia informa i centri nazionali di coordinamento di qualsiasi episodio avvenuto nella zona pre-frontaliera.</p>\n</div>"]]}, "12": {"label": "Articolo 12", "heading": "Applicazione comune degli strumenti di sorveglianza", "anchor": "art_12", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia coordina l'applicazione comune degli strumenti di sorveglianza, al fine di fornire ai centri nazionali di coordinamento e a sé medesima informazioni sulla sorveglianza delle frontiere esterne e della zona pre-frontaliera su base regolare e in modo affidabile ed economicamente efficiente.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia fornisce a un centro nazionale di coordinamento, su sua richiesta, informazioni sulle frontiere esterne dello Stato membro richiedente e sulla zona pre-frontaliera, che possono essere ottenute tramite:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">monitoraggio selettivo di porti e coste del paese terzo designato che, tramite analisi dei rischi e informazioni, risultino essere punti di imbarco o di transito di imbarcazioni o altri mezzi utilizzati per l'immigrazione clandestina o la criminalità transfrontaliera;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">localizzazione in alto mare di imbarcazioni o altro mezzo utilizzati, o che si sospetta siano utilizzati, per l'immigrazione clandestina o la criminalità transfrontaliera;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">monitoraggio di aree designate nel settore marittimo al fine di individuare, identificare e localizzare imbarcazioni e altri mezzi utilizzati, o che si sospetta siano utilizzati, per l'immigrazione clandestina o la criminalità transfrontaliera;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">valutazione ambientale di aree designate nel settore marittimo e alla frontiera esterna terrestre, allo scopo di ottimizzare le attività di monitoraggio e pattugliamento;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">monitoraggio selettivo di zone pre-frontaliere designate lungo le frontiere esterne che, tramite analisi dei rischi e informazioni, risultino essere potenziali aree di partenza o di transito dell'immigrazione clandestina o della criminalità transfrontaliera.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Agenzia fornisce le informazioni di cui al paragrafo 1 combinando e analizzando dati che possono essere raccolti dai sistemi, dai sensori e dalle piattaforme seguenti:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sistemi di segnalazione delle navi, secondo le rispettive basi giuridiche;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">immagini satellitari;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sensori montati su qualsiasi veicolo, imbarcazione o altro mezzo.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L'Agenzia può respingere una richiesta presentata da un centro nazionale di coordinamento per motivi tecnici, finanziari od operativi. L'Agenzia notifica al centro nazionale di coordinamento, a tempo debito, i motivi di tale diniego.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   L'Agenzia può utilizzare di propria iniziativa gli strumenti di sorveglianza di cui al paragrafo 2 al fine di raccogliere informazioni utili per il quadro comune di intelligence pre-frontaliera.</p>\n</div>"]]}, "13": {"label": "Articolo 13", "heading": "Trattamento dei dati personali", "anchor": "art_13", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Quando il quadro situazionale nazionale è utilizzato per il trattamento dei dati personali, tali dati sono trattati in conformità della direttiva 95/46/CE, della decisione quadro 2008/977/GAI e delle pertinenti disposizioni nazionali in materia di protezione dei dati.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il quadro situazionale europeo e il quadro comune di intelligence pre-frontaliera possono essere utilizzati solo per il trattamento dei dati personali relativi al numero di identificazione delle imbarcazioni.</p>\n<p class=\"oj-normal\">Tali dati sono trattati conformemente all'articolo 11 quater bis del regolamento (CE) n. 2007/2004. Essi sono trattati esclusivamente ai fini dell'individuazione, dell'identificazione e della localizzazione delle imbarcazioni e per gli scopi di cui all'articolo 11 quater, paragrafo 3, di tale regolamento. Essi sono automaticamente cancellati entro sette giorni dalla ricezione da parte dell'Agenzia o, qualora occorra più tempo per localizzare una nave, entro due mesi dalla ricezione.</p>\n</div>"]]}, "14": {"label": "Articolo 14", "heading": "Determinazione delle sezioni di frontiera esterna", "anchor": "art_14", "frags": [[null, "<p class=\"oj-normal\">Ai fini del presente regolamento, ogni Stato membro suddivide le sue frontiere esterne terrestri e marittime in sezioni di frontiera e le notifica all'Agenzia.</p>"]]}, "15": {"label": "Articolo 15", "heading": "Assegnazione di livelli di impatto alle sezioni di frontiera esterna", "anchor": "art_15", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Sulla base dell'analisi dei rischi eseguita dall'Agenzia e di concerto con lo Stato membro interessato, l'Agenzia assegna i seguenti livelli di impatto a ciascuna delle sezioni di frontiera esterna terrestre e marittima degli Stati membri o li modifica:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">livello di impatto basso, qualora gli episodi connessi all'immigrazione clandestina o alla criminalità transfrontaliera che si verificano nella pertinente sezione di frontiera abbiano un impatto irrilevante sulla sicurezza della frontiera;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">livello di impatto medio, qualora gli episodi connessi all'immigrazione clandestina o alla criminalità transfrontaliera che si verificano nella pertinente sezione di frontiera abbiano un impatto moderato sulla sicurezza della frontiera;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">livello di impatto alto, qualora gli episodi connessi all'immigrazione clandestina o alla criminalità transfrontaliera che si verificano nella pertinente sezione di frontiera abbiano un impatto significativo sulla sicurezza della frontiera.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il centro nazionale di coordinamento valuta periodicamente se sia necessario modificare il livello di impatto di una sezione di frontiera tenendo conto delle informazioni contenute nel quadro situazionale nazionale.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Agenzia visualizza i livelli di impatto assegnati alle frontiere esterne nel quadro situazionale europeo.</p>\n</div>"]]}, "16": {"label": "Articolo 16", "heading": "Determinazione delle sezioni di frontiera esterna", "anchor": "art_16", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri si assicurano che le attività di sorveglianza svolte alle sezioni di frontiera esterna corrispondano ai livelli di impatto attribuiti, nei modi seguenti:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">se ad una sezione di frontiera esterna è attribuito un livello di impatto basso, le autorità nazionali responsabili della sorveglianza delle frontiere esterne organizzano una sorveglianza regolare sulla base delle analisi dei rischi e provvedono affinché nella zona di frontiera siano presenti personale e risorse sufficienti pronti alla localizzazione, all'identificazione e all'intercettazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">se ad una sezione di frontiera esterna è attribuito un livello di impatto medio, le autorità nazionali incaricate della sorveglianza delle frontiere esterne provvedono affinché siano adottate, per detta sezione di frontiera, misure di sorveglianza adeguate oltre alle misure di cui alla lettera a). L'adozione di tali misure di sorveglianza è notificata al centro nazionale di coordinamento. Il centro nazionale di coordinamento coordina ogni sostegno dato in conformità dell'articolo 5, paragrafo 3;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">se ad una sezione di frontiera esterna è attribuito un livello di impatto alto, lo Stato membro interessato provvede, mediante il centro nazionale di coordinamento, affinché le autorità nazionali che operano presso tale sezione di frontiera ricevano il sostegno necessario e siano adottate misure di sorveglianza rafforzate oltre alle misure di cui alla lettera b). Detto Stato membro può chiedere sostegno all'Agenzia alle condizioni previste dal regolamento (CE) n. 2007/2004 per l'avvio di operazioni congiunte o interventi rapidi.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il centro nazionale di coordinamento informa regolarmente l'Agenzia delle misure adottate a livello nazionale a norma del paragrafo 1, lettera c).</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Se ad una sezione di frontiera esterna, adiacente a una sezione di frontiera di un altro Stato membro o di un paese con cui esistono accordi o reti regionali di cui agli articoli 19 e 20, è attribuito un livello di impatto medio o alto, il centro nazionale di coordinamento contatta il centro nazionale di coordinamento dello Stato membro vicino o l'autorità competente del paese vicino e si adopera per coordinare le necessarie misure transfrontaliere.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Quando uno Stato membro presenta una richiesta a norma del paragrafo 1, lettera c), l'Agenzia, nel rispondere a tale richiesta, può sostenere tale Stato membro, in particolare:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">riservando un trattamento prioritario all'applicazione comune degli strumenti di sorveglianza;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">coordinando l'impiego di squadre europee di guardie di frontiera ai sensi del regolamento (CE) n. 2007/2004;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">garantendo l'impiego di attrezzature tecniche a disposizione dell'Agenzia ai sensi del regolamento (CE) n. 2007/2004;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">coordinando ogni forma di sostegno supplementare offerta da altri Stati membri.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   L'Agenzia valuta, insieme allo Stato membro interessato, l'attribuzione dei livelli di impatto e le misure corrispondenti adottate a livello nazionale e dell'Unione nelle sue relazioni di analisi dei rischi.</p>\n</div>"]]}, "17": {"label": "Articolo 17", "heading": "Assegnazione di compiti ad altre autorità degli Stati membri", "anchor": "art_17", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri possono incaricare autorità regionali, locali, funzionali o di altro tipo, che siano in grado di adottare decisioni operative, di assicurare la conoscenza situazionale e la capacità di reazione nelle rispettive aree di competenza, nonché i compiti e le competenze di cui all'articolo 5, paragrafo 3, lettere c), e) e f).</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La decisione degli Stati membri di ripartire i compiti in conformità del paragrafo 1 non compromette la capacità del centro nazionale di coordinamento di cooperare e scambiare informazioni con altri centri nazionali di coordinamento e con l'Agenzia.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   In casi prestabiliti, determinati a livello nazionale, il centro nazionale di coordinamento può autorizzare un'autorità di cui al paragrafo 1 a comunicare e scambiare informazioni con le autorità regionali o il centro nazionale di coordinamento di un altro Stato membro o le autorità competenti di un paese terzo, a condizione che tale autorità informi regolarmente il suo centro nazionale di coordinamento di tali comunicazioni e scambi di informazioni.</p>\n</div>"]]}, "18": {"label": "Articolo 18", "heading": "Cooperazione dell'Agenzia con terzi", "anchor": "art_18", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia può utilizzare informazioni, capacità e sistemi esistenti disponibili presso altri organi, organismi e servizi dell'Unione e organizzazioni internazionali, nell'ambito dei rispettivi quadri giuridici.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   A norma del paragrafo 1, l'Agenzia coopera in particolare con le istituzioni, gli organi, gli organismi e i servizi dell'Unione e le organizzazioni internazionali seguenti:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'Ufficio europeo di polizia (Europol), per lo scambio di informazioni sulla criminalità transfrontaliera da inserire nel quadro situazionale europeo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il Centro satellitare dell'Unione europea, l'Agenzia europea per la sicurezza marittima e l'Agenzia europea di controllo della pesca, nel fornire l'applicazione comune degli strumenti di sorveglianza;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la Commissione, il servizio europeo per l'azione esterna, gli organi, gli organismi e servizi dell'Unione e l'Ufficio europeo di sostegno per l'asilo, che possono fornire all'Agenzia informazioni utili per aggiornare il quadro situazionale europeo e il quadro comune di intelligence pre-frontaliera;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le organizzazioni internazionali che possono fornire all'Agenzia informazioni utili per aggiornare il quadro situazionale europeo e il quadro comune di intelligence pre-frontaliera.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Ai sensi del paragrafo 1, l'Agenzia può cooperare con il Centro di analisi e operazioni contro il narcotraffico marittimo (MAOC-N) e il Centre de Coordination pour la lutte antidrogue en Méditerranée (CeCLAD-M), per lo scambio di informazioni sulla criminalità transfrontaliera da inserire nel quadro situazionale europeo.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Lo scambio di informazioni tra l'Agenzia e gli organi, gli organismi e i servizi dell'Unione e le organizzazioni internazionali di cui ai paragrafi 2 e 3 avviene tramite la rete di comunicazione di cui all'articolo 7 o altre reti di comunicazione che rispondano ai criteri di disponibilità, riservatezza e integrità.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   La cooperazione tra l'Agenzia e gli organi, gli organismi e i servizi dell'Unione e le organizzazioni internazionali di cui ai paragrafi 2 e 3 è disciplinata quale parte di accordi di lavoro in conformità del regolamento (CE) n. 2007/2004 e della base giuridica di ciascun organo, organismo o servizio dell'Unione o organizzazione internazionale interessati. Per quanto riguarda il trattamento delle informazioni classificate, tali accordi prevedono che l'organismo, l'ufficio o l'agenzia dell'Unione o l'organizzazione internazionale interessati rispettino regole e norme di sicurezza equivalenti a quelle applicate dall'Agenzia.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Gli organi, gli organismi e i servizi dell'Unione e le organizzazioni internazionali di cui ai paragrafi 2 e 3 usano le informazioni ricevute nel contesto di EUROSUR esclusivamente entro i limiti del rispettivo quadro giuridico e nel rispetto dei diritti fondamentali, compresi gli obblighi di protezione dei dati.</p>\n</div>"]]}, "19": {"label": "Articolo 19", "heading": "Cooperazione con l'Irlanda e il Regno Unito", "anchor": "art_19", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Ai fini del presente regolamento lo scambio di informazioni e la cooperazione con l'Irlanda e il Regno Unito possono avvenire sulla base di accordi bilaterali o multilaterali tra l'Irlanda o il Regno Unito rispettivamente e uno o più Stati membri vicini o attraverso reti regionali basate su tali accordi. I centri nazionali di coordinamento degli Stati membri rappresentano i punti di contatto per lo scambio di informazioni con le omologhe autorità dell'Irlanda e del Regno Unito nel quadro di EUROSUR. Tali accordi, una volta conclusi, sono notificati alla Commissione.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli accordi di cui al paragrafo 1 sono limitati agli scambi di informazioni tra il centro nazionale di coordinamento di uno Stato membro e la corrispondente autorità dell'Irlanda o del Regno Unito relativi a:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">informazioni contenute nel quadro situazionale nazionale di uno Stato membro nella misura in cui sono trasmesse all'Agenzia ai fini del quadro situazionale europeo e del quadro comune di intelligence pre-frontaliera;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">informazioni raccolte dall'Irlanda e dal Regno Unito che siano utili ai fini del quadro situazionale europeo e del quadro comune di intelligence pre-frontaliera;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">informazioni di cui all'articolo 9, paragrafo 9.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Le informazioni fornite nel contesto di EUROSUR dall'Agenzia o da uno Stato membro che non sia parte di un accordo di cui al paragrafo 1 non sono condivise con l'Irlanda o il Regno Unito senza la previa approvazione dell'Agenzia o di tale Stato membro. Il rifiuto di scambiare tali informazioni con l'Irlanda o il Regno Unito vincola gli Stati membri e l'Agenzia.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Sono vietate la trasmissione ulteriore o altra comunicazione di informazioni scambiate ai sensi del presente articolo a paesi terzi o a parti terze.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Gli accordi di cui al paragrafo 1 comprendono disposizioni sui costi finanziari derivanti dalla partecipazione dell'Irlanda e del Regno Unito all'attuazione degli accordi stessi.</p>\n</div>"]]}, "20": {"label": "Articolo 20", "heading": "Cooperazione con i paesi terzi vicini", "anchor": "art_20", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Ai fini del presente regolamento gli Stati membri possono scambiare informazioni e cooperare con uno o più paesi terzi vicini. Tale scambio di informazioni e tale cooperazione avvengono sulla base di accordi bilaterali o multilaterali o attraverso reti regionali istituite in base a detti accordi. I centri nazionali di coordinamento degli Stati membri rappresentano i punti di contatto per lo scambio di informazioni con i paesi terzi vicini.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Prima che sia concluso un accordo di cui al paragrafo 1, gli Stati membri interessati lo notificano alla Commissione, la quale verifica che le disposizioni che sono pertinenti per EUROSUR siano conformi al presente regolamento. Una volta concluso, gli Stati membri interessati notificano l’accordo alla Commissione, che ne informa il Parlamento europeo, il Consiglio e l'Agenzia.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli accordi di cui al paragrafo 1 sono conformi al pertinente diritto dell'Unione e internazionale sui diritti fondamentali e sulla protezione internazionale, inclusa la Carta dei diritti fondamentali dell'Unione europea e la Convenzione relativa allo status dei rifugiati, in particolare il principio di non respingimento.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Lo scambio di dati personali con paesi terzi nel quadro di EUROSUR è rigorosamente limitato a quanto assolutamente necessario ai fini del presente regolamento. È effettuato in conformità della direttiva 95/46/CE, della decisione quadro 2008/977/GAI e delle pertinenti disposizioni nazionali in materia di protezione dei dati.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   È vietato ogni scambio di informazioni ai sensi del paragrafo 1 che fornisca a un paese terzo informazioni che potrebbero essere utilizzate da un paese terzo per identificare persone o gruppi di persone la cui richiesta di accesso alla protezione internazionale è in fase d'esame o che rischiano gravemente di essere sottoposte a tortura, trattamenti o pene inumani o degradanti o altra violazione dei diritti fondamentali.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Lo scambio di informazioni ai sensi del paragrafo 1 è conforme alle condizioni degli accordi bilaterali e multilaterali conclusi con paesi terzi vicini.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Le informazioni fornite nel contesto di EUROSUR dall'Agenzia o da uno Stato membro che non sia parte di un accordo di cui al paragrafo 1 non sono condivise con un paese terzo nell'ambito di tale accordo senza la previa approvazione dell'Agenzia o di tale Stato membro. Il rifiuto di condividere tali informazioni con il paese terzo interessato vincola gli Stati membri e l'Agenzia.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Sono vietate la trasmissione ulteriore o altra comunicazione di informazioni scambiate ai sensi del presente articolo ad altri paesi terzi o a parti terze.</p>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   Qualsiasi scambio con paesi terzi di informazioni acquisite mediante l'applicazione comune degli strumenti di sorveglianza è soggetto al diritto e alle regole che disciplinano tali strumenti e alle pertinenti disposizioni della direttiva 95/46/CE, del regolamento (CE) n. 45/2001 e della decisione quadro 2008/977/GAI.</p>\n</div>"]]}, "21": {"label": "Articolo 21", "heading": "Manuale", "anchor": "art_21", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   La Commissione, in stretta cooperazione con gli Stati membri, con l'Agenzia e con ogni altro organismo, ufficio o agenzia dell'Unione competente, pubblica un manuale pratico per l'attuazione e la gestione di EUROSUR («manuale»). Il manuale fornisce orientamenti tecnici e operativi, raccomandazioni e migliori prassi, anche in merito alla cooperazione con paesi terzi. La Commissione adotta il manuale mediante una raccomandazione.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La Commissione può decidere, previa consultazione degli Stati membri e dell'Agenzia, di classificare parti del manuale come RESTREINT UE/EU RESTRICTED secondo le norme stabilite nel regolamento interno della Commissione.</p>\n</div>"]]}, "22": {"label": "Articolo 22", "heading": "Monitoraggio e valutazione", "anchor": "art_22", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Ai fini del presente regolamento l'Agenzia e gli Stati membri garantiscono che siano applicate procedure per monitorare il funzionamento tecnico e operativo di EUROSUR in funzione degli obiettivi da conseguire, ossia adeguate conoscenza situazionale e capacità di reazione alle frontiere esterne, e il rispetto dei diritti fondamentali, compreso il principio di non respingimento.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Entro il 1<span class=\"oj-super\">o</span> dicembre 2015, e in seguito ogni due anni, l'Agenzia presenta al Parlamento europeo e al Consiglio una relazione sul funzionamento di EUROSUR.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Entro 1<span class=\"oj-super\">o</span> dicembre 2016, e in seguito ogni quattro anni, la Commissione presenta al Parlamento europeo e al Consiglio una valutazione generale di EUROSUR. Tale valutazione comprende un esame dei risultati conseguiti rispetto agli obiettivi fissati, della persistenza della validità delle motivazioni di base, dell'applicazione del presente regolamento negli Stati membri e da parte dell'Agenzia, del rispetto dei diritti fondamentali e dell'impatto sugli stessi. Contiene inoltre una valutazione costi-benefici. La valutazione è corredata, se del caso, di adeguate proposte di modifica del presente regolamento.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli Stati membri trasmettono all'Agenzia le informazioni necessarie per elaborare la relazione di cui al paragrafo 2.</p>\n<p class=\"oj-normal\">L'Agenzia fornisce alla Commissione le informazioni necessarie per elaborare la valutazione di cui al paragrafo 3.</p>\n</div>"]]}, "23": {"label": "Articolo 23", "heading": "Modifiche del regolamento (CE) n. 2007/2004", "anchor": "art_23", "frags": [[null, "<p class=\"oj-normal\">Il regolamento (CE) n. 2007/2004 è così modificato:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">1)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">all'articolo 2, paragrafo 1, la lettera i) è sostituita dalla seguente:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">«i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">presta la necessaria assistenza per sviluppare e gestire un sistema europeo di sorveglianza di frontiera e, ove opportuno, per sviluppare un ambiente comune di condivisione delle informazioni, compresa l'interoperabilità dei sistemi, in particolare istituendo, aggiornando e coordinando il quadro di EUROSUR conformemente al regolamento (UE) n. 1052/2013 del Parlamento europeo e del Consiglio (<span class=\"oj-super oj-note-tag\">*1</span>)\n</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-note\">\n(<span class=\"oj-super\">*1</span>)  Regolamento (UE) n. 1052/2013 del Parlamento europeo e del Consiglio, del 22 ottobre 2013, che istituisce il sistema europeo di sorveglianza delle frontiere (EUROSUR) (GU L 295 del 6.11.2013, pag. 11).»;\"\n                        </p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">2)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">è inserito l'articolo seguente:</p>\n<div>\n<p class=\"oj-ti-art\">«Articolo 11 quater bis</p>\n<p class=\"oj-sti-art\">Trattamento dei dati personali nel quadro di EUROSUR</p>\n<p class=\"oj-normal\">L'Agenzia può trattare dati personali ai sensi dell'articolo 13, paragrafo 2, del regolamento (UE) n. 1052/2013, che si applica in conformità delle misure di cui all'articolo 11 bis del presente regolamento. In particolare, il trattamento di tali dati rispetta i principi di necessità e proporzionalità e sono vietate la trasmissione ulteriore o altra comunicazione di tali dati personali trattati dall'Agenzia a paesi terzi.».</p>\n</div>\n</td>\n</tr>\n</tbody>\n</table>"]]}, "24": {"label": "Articolo 24", "heading": "Entrata in vigore e applicazione", "anchor": "art_24", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il presente regolamento entra in vigore il ventesimo giorno successivo alla pubblicazione nella <span class=\"oj-italic\">Gazzetta ufficiale dell'Unione europea</span>.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il presente regolamento si applica a decorrere dal 2 dicembre 2013.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   La Bulgaria, l’Estonia, la Grecia, la Spagna, la Francia, la Croazia, l’Italia, Cipro, la Lettonia, la Lituania, l’Ungheria, Malta, la Polonia, il Portogallo, la Romania, la Slovenia, la Slovacchia e la Finlandia istituiscono un centro nazionale di coordinamento in conformità dell'articolo 5 a decorrere dal 2 dicembre 2013.</p>\n<p class=\"oj-normal\">Gli altri Stati membri istituiscono un centro nazionale di coordinamento in conformità dell'articolo 5 a decorrere dal 1<span class=\"oj-super\">o</span> dicembre 2014.</p>\n</div>"]]}}, "recitals": {}};